/**
 * Returns the allowed Māori cultural terms, newline-separated.
 * In production this reads from the Rust-generated bindings.
 */
export async function allowedCulturalTerms(): Promise<string> {
  return [
    'Whakatā',
    'Mahi',
    'Tikanga',
    'Mana',
    'Māori',
    'Whakapapa',
    'Kōrero',
    'Whenua',
    'Tangata',
    'Aroha',
  ].join('\n');
}
